import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as l,o as d,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"IP Geolocation اور User Management","description":"","frontmatter":{},"headers":[],"relativePath":"ur/Other/ip-geolocation-and-user-management.md","filePath":"ur/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"ur/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return d(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-اور-user-management" tabindex="-1">IP Geolocation اور User Management <a class="header-anchor" href="#ip-geolocation-اور-user-management" aria-label="Permalink to &quot;IP Geolocation اور User Management&quot;">​</a></h1><p>IP geolocation uploader records، login devices، اور ملتے جلتے logs میں موجود IP addresses کو approximate locations میں بدلتا ہے۔</p><p>configure ہونے کے بعد admin panel upload اور access origins زیادہ واضح دکھا سکتا ہے۔ User Management مشکوک IP addresses کے لیے upload access block یا restore کرنے کی سہولت بھی دیتا ہے۔</p><h2 id="کہاں-configure-کریں" tabindex="-1">کہاں Configure کریں <a class="header-anchor" href="#کہاں-configure-کریں" aria-label="Permalink to &quot;کہاں Configure کریں&quot;">​</a></h2><p>کھولیں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>نیا IP geolocation flow ایک map service پر depend کرنے کے بجائے multiple sources support کرتا ہے۔</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>display language منتخب کرتا ہے، جیسے English، Simplified Chinese، Japanese، French، وغیرہ۔</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind GeoLite Web Service کے لیے MaxMind account ID۔</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key۔</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key۔ Chinese addresses اور mainland China IPs کے لیے مفید۔</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key۔ multilingual IP geolocation support کرتا ہے۔</td></tr></tbody></table><p>صرف وہ services بھریں جن کی آپ کو ضرورت ہے۔ ہر field configure کرنا ضروری نہیں۔</p><p>اگر کوئی key فراہم نہ کی جائے تو ImgBed built-in free sources try کرتا ہے، مگر stability، language support، اور precision خود configured service سے کم ہو سکتی ہے۔</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>اگر آپ کو بنیادی طور پر Chinese addresses چاہیے:</p><ol><li>IP geolocation language کو Simplified Chinese پر set کریں۔</li><li>Tencent Map Key configure کریں۔</li><li>optionally MaxMind یا ipapi کو fallback source کے طور پر شامل کریں۔</li></ol><p>اگر آپ کو English یا multilingual addresses چاہیے:</p><ol><li>مطلوبہ language منتخب کریں۔</li><li>MaxMind Account ID اور License Key configure کریں۔</li><li>multilingual results بہتر چاہیے ہوں تو ipapi Key شامل کریں۔</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind کو چاہیے:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>MaxMind dashboard میں account ID تلاش کریں اور License Keys page سے License Key generate کریں۔</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>generation کے بعد Account ID اور License Key ImgBed میں paste کر کے save کریں۔</p><p>MaxMind کا free plan روزمرہ استعمال کے لیے کافی ہے، مگر request limits موجود ہیں۔ quota exceed ہو جائے تو ImgBed باقی available sources try کرتا رہتا ہے۔</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi APILayer API Key استعمال کرتا ہے۔</p><p>ipapi console کھولیں اور وہاں دکھائی گئی API Key copy کریں۔</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>اسے ImgBed کے <code>ipapi Key</code> field میں paste کریں اور save کریں۔</p><p>ipapi multilingual IP geolocation support کرتا ہے اور اس وقت useful ہے جب آپ selected language میں addresses دکھانا چاہتے ہیں۔ اس کے free plan میں بھی request limits ہیں۔ quota ختم ہو جائے تو ImgBed باقی available sources try کرتا ہے۔</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key Chinese addresses، خاص طور پر mainland China IPs کے لیے مفید ہے۔</p><p>Tencent Location Service میں key بناتے وقت enable کریں:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>creation کے بعد key کو <code>Tencent Map Key</code> میں paste کریں اور save کریں۔</p><p>اگر صرف basic Chinese IP geolocation چاہیے تو Tencent Map Key شروع کرنے کے لیے کافی ہے۔</p><h2 id="user-management-میں-کیا-چیک-کریں" tabindex="-1">User Management میں کیا چیک کریں <a class="header-anchor" href="#user-management-میں-کیا-چیک-کریں" aria-label="Permalink to &quot;User Management میں کیا چیک کریں&quot;">​</a></h2><p>User Management admin panel کے اوپر سے available ہے۔</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management IP کے حساب سے upload activity دکھاتا ہے:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>uploader کا source IP۔</td></tr><tr><td>Address</td><td>IP سے resolve ہونے والی approximate location۔</td></tr><tr><td>Total upload size</td><td>اس IP سے upload ہونے والی total file size۔</td></tr><tr><td>Upload count</td><td>اس IP سے uploads کی تعداد۔</td></tr><tr><td>Upload allowed</td><td>On کا مطلب uploads allowed ہیں۔ Off کا مطلب uploads blocked ہیں۔</td></tr></tbody></table><p>بائیں arrow پر کلک کر کے اس IP سے uploaded files کی list expand کریں۔</p><p>file list file name، preview، file size، moderation result، file status، اور upload time دکھاتی ہے۔ uploads مشکوک لگیں تو پہلے IP expand کریں، files review کریں، پھر decide کریں کہ further uploads block کرنی ہیں یا نہیں۔</p><p>اگر IP suspicious ہو تو <code>Upload allowed</code> off کریں۔ اس IP سے future uploads block ہو جائیں گے۔</p><h2 id="search-sort-اور-advanced-filters" tabindex="-1">Search, Sort, اور Advanced Filters <a class="header-anchor" href="#search-sort-اور-advanced-filters" aria-label="Permalink to &quot;Search, Sort, اور Advanced Filters&quot;">​</a></h2><p>User Management کے اوپر IP source یا address سے search کریں۔</p><p>recent uploaders، high-frequency uploaders، یا high-usage IPs تلاش کرنے کے لیے time، upload count، یا total upload size سے sort کریں۔</p><p>گہری investigation کے لیے advanced filters کھولیں۔</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters support کرتے ہیں:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>selected period میں files upload کرنے والے IPs دکھاتا ہے۔</td></tr><tr><td>Access status</td><td>normal، blocked، اور ملتے جلتے states سے filter کرتا ہے۔</td></tr><tr><td>Allow/block list</td><td>allowlist، blocklist، یا unset سے filter کرتا ہے۔</td></tr><tr><td>File type</td><td>images، videos، audio، documents، code، یا other files upload کرنے والے IPs دکھاتا ہے۔</td></tr><tr><td>File size</td><td>uploaded file size range سے filter کرتا ہے۔</td></tr><tr><td>Age rating</td><td>unset، General، R12+، R16+، R18، اور ملتی جلتی ratings سے filter کرتا ہے۔</td></tr><tr><td>File status</td><td>abnormal files investigate کرنے کے لیے current file status سے filter کرتا ہے۔</td></tr></tbody></table><p>apply کرنے کے لیے <code>Apply Filters</code> پر کلک کریں۔ تمام data پر واپس آنے کے لیے <code>Reset</code> استعمال کریں۔</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>mobile پر User Management card layout میں بدل جاتا ہے۔</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>ہر card IP، address، total upload size، upload count، اور upload allowed switch دکھاتا ہے۔ آپ horizontal table scrolling کے بغیر users manage کر سکتے ہیں۔</p><h2 id="اگر-location-غلط-لگے" tabindex="-1">اگر Location غلط لگے <a class="header-anchor" href="#اگر-location-غلط-لگے" aria-label="Permalink to &quot;اگر Location غلط لگے&quot;">​</a></h2><p>IP geolocation approximate ہے۔ یہ precise street address نہیں۔</p><p>اگر user proxy، data center، cloud server، یا cross-border network کے پیچھے ہے، دکھائی گئی location real location سے مختلف ہو سکتی ہے۔</p><p>اس feature کو rough origin سمجھنے، abnormal uploads تلاش کرنے، اور blocking decisions میں مدد کے لیے استعمال کریں۔ اسے precise tracking نہ سمجھیں۔</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address empty ہے</td><td>IP شاید ابھی resolve نہیں ہوا، یا current source temporarily unavailable ہے۔</td></tr><tr><td>Address language غلط ہے</td><td>IP geolocation language اور اس language کو support کرنے والے source کی configuration چیک کریں۔</td></tr><tr><td>Address data center دکھاتا ہے</td><td>بہت سے proxies، cloud servers، اور crawlers data center یا ISP addresses کے طور پر دکھتے ہیں۔</td></tr><tr><td>Upload count high ہے</td><td>اس IP کو غور سے review کریں اور ضرورت ہو تو uploads block کریں۔</td></tr><tr><td>Total upload size large ہے</td><td>sort یا filter کریں، IP expand کریں، اور specific files inspect کریں۔</td></tr><tr><td>blocking کے بعد restore کرنا ہے</td><td><code>Upload allowed</code> دوبارہ on کریں۔</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Other Settings میں IP Geolocation کھولیں</span></span>
<span class="line"><span>-&gt; IP geolocation language منتخب کریں</span></span>
<span class="line"><span>-&gt; ضرورت کے مطابق MaxMind, Tencent Map, یا ipapi credentials بھریں</span></span>
<span class="line"><span>-&gt; settings save کریں</span></span>
<span class="line"><span>-&gt; User Management کھولیں</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size, اور upload count review کریں</span></span>
<span class="line"><span>-&gt; abnormal IPs تلاش کرنے کے لیے search, sort, یا advanced filters استعمال کریں</span></span>
<span class="line"><span>-&gt; ضرورت کے مطابق uploads allow یا block کریں</span></span></code></pre></div>`,64)])])}const x=l(c,[["render",u]]);export{P as __pageData,x as default};
